const ListAgents = `-- name: ListAgents :many
SELECT id, slug, title, description, tags, avatar, background_color, plugins, client_id, user_id, chat_config, few_shots, model, params, provider, system_role, tts, "virtual", opening_message, opening_questions, created_at, updated_at FROM agents
WHERE user_id = ?
ORDER BY updated_at DESC
LIMIT ? OFFSET ?
`

type ListAgentsParams struct {
	UserID string `json:"userId"`
	Limit  int64  `json:"limit"`
	Offset int64  `json:"offset"`
}

func (q *Queries) ListAgents(ctx context.Context, arg ListAgentsParams) ([]Agent, error) {
	rows, err := q.db.QueryContext(ctx, ListAgents, arg.UserID, arg.Limit, arg.Offset)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []Agent{}
	for rows.Next() {
		var i Agent
		if err := rows.Scan(
			&i.ID,
			&i.Slug,
			&i.Title,
			&i.Description,
			&i.Tags,
			&i.Avatar,
			&i.BackgroundColor,
			&i.Plugins,
			&i.ClientID,
			&i.UserID,
			&i.ChatConfig,
			&i.FewShots,
			&i.Model,
			&i.Params,
			&i.Provider,
			&i.SystemRole,
			&i.Tts,
			&i.Virtual,
			&i.OpeningMessage,
			&i.OpeningQuestions,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

